// // When the enable signal (en) is high (0), the module outputs the value from input in1. When the enable signal is low (1), the output is taken from input in2.
module top_module(
    // ports
    output wire out,
    input wire in1,
    input wire in2,
    input wire en
);// internal signals
    wire mux_output;

    // 2-to-1 multiplexer
    assign mux_output = (en == 1'b0) ? in1 : in2;

    // output
    assign out = mux_output;

endmodule
